INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (1, 1, 1, 'AE1', 'Diferenciar movimentos coreográficos em danças folclóricas de diferentes épocas.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (2, 1, 1, 'AE2', 'Experimentar composições coreográficas autorais com base em elementos das danças folclóricas brasileiras.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (3, 1, 1, 'AE3', 'Analisar os gêneros da música brasileira a partir de seus contextos de produção, circulação e apreciação.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (4, 1, 1, 'AE4', 'Criar composições musicais, por meio da voz, sons corporais e instrumentos não convencionais, traduzindo-as em partituras criativas.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (5, 1, 2, 'AE1', 'Relacionar elementos estruturais, origens e contextos das danças clássicas e modernas a partir da apreciação de diferentes artistas e grupos.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (6, 1, 2, 'AE2', 'Experimentar as variações dos fatores do movimento (tempo, peso, fluência e espaço) na prática da dança.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (7, 1, 2, 'AE3', 'Analisar as funções sociais e políticas da música clássica e do canto coral, considerando seus contextos históricos.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (8, 1, 2, 'AE4', 'Criar composições musicais coletivamente, por meio de práticas de improvisação.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (9, 1, 2, 'AE5', 'Investigar instrumentos acústicos, reconhecendo seus timbres.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (10, 1, 3, 'AE1', 'Analisar composições de danças coletivas de diferentes matrizes culturais brasileiras para apreciá-las.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (11, 1, 3, 'AE2', 'Explorar as variações dos fatores do movimento (tempo, fluência e espaço) explorando-os na prática da dança.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (12, 1, 3, 'AE3', 'Compor sequências coreográficas a partir de repertório e vocabulário específico da dança.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (13, 1, 3, 'AE4', 'Explorar músicas de diferentes matrizes brasileiras e africanas, reconhecendo características, usos, funções e timbres de instrumentos musicais diversos.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (14, 1, 3, 'AE5', 'Analisar os elementos das músicas indígenas como uma das matrizes culturais brasileiras, utilizando canções, jogos e apreciando as composições.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (15, 1, 3, 'AE6', 'Expressar ideias musicais de forma individual e coletiva, por meio da improvisação e composição com voz, sons corporais e instrumentos variados.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (16, 1, 4, 'AE1', 'Analisar o uso de elementos cênicos (figurino, cenário, iluminação, espaços e tecnologias digitais) nos contextos de criação coreográfica e apresentações de dança.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (17, 1, 4, 'AE2', 'Explorar brincadeiras e jogos no processo de criação coreográfica em dança contemporânea, integrando tecnologias digitais nas apresentações.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (18, 1, 4, 'AE3', 'Analisar funções e estéticas dos diferentes gêneros da música popular brasileira e estrangeira, considerando seu contexto histórico e social.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (19, 1, 4, 'AE4', 'Compor e decompor músicas, explorando variações de timbre, altura, intensidade, melodia e ritmo com uso de diversas tecnologias, inclusive as digitais.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (20, 1, 5, 'AE1', 'Analisar o funcionamento das linguagens artísticas em suas dimensões visuais, verbais, sonoras e gestuais para a interpretação e a produção de discursos presentes na mídia e em obras de diversos artistas.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (21, 1, 5, 'AE2', 'Utilizar as linguagens artísticas, analisando sua aplicabilidade e sua função como fenômeno social, cultural, histórico, político e econômico.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (22, 1, 5, 'AE3', 'Interpretar discursos midiáticos, identificando visões de mundo e interesses, para posicionar-se contra preconceitos e ideologias presentes na mídia.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (23, 1, 5, 'AE4', 'Explorar as práticas de linguagem, discutindo os princípios e desafios contemporâneos, e atuando de forma crítica, criativa, solidária e ética.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (24, 1, 5, 'AE5', 'Experimentar processos de criação em diversas linguagens artísticas, considerando seus aspectos formais, seus funcionamentos e a produção de sentido, em diferentes contextos.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (25, 9, 1, 'AE1', 'Compor e decompor números naturais de diferentes ordens, reconhecendo as características do sistema de numeração decimal.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (26, 9, 1, 'AE2', 'Comparar e ordenar números naturais de diferentes ordens, utilizando, inclusive, a reta numérica como suporte.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (27, 9, 1, 'AE3', 'Resolver problemas envolvendo as quatro operações fundamentais com números naturais, por meio de estratégias variadas.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (28, 9, 1, 'AE4', 'Resolver problemas envolvendo múltiplos e divisores de números naturais, utilizando-os para ampliar as estratégias de cálculo.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (29, 9, 1, 'AE5', 'Resolver problemas envolvendo cálculo da fração de uma quantidade, cujo resultado é um número natural.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (30, 9, 1, 'AE6', 'Comparar e ordenar frações, utilizando equivalência, representações visuais e a reta numérica como apoio.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (31, 9, 1, 'AE7', 'Resolver problemas que envolvam adição ou subtração de números racionais positivos na representação fracionária, por meio de estratégias diversas.', 7, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (32, 9, 1, 'AE8', 'Classificar polígonos, considerando lados, vértices e ângulos, diferenciando os regulares dos não regulares.', 8, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (33, 9, 1, 'AE9', 'Classificar triângulos em relação às medidas dos lados.', 9, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (34, 9, 1, 'AE10', 'Classificar quadriláteros em relação às medidas dos lados e ângulos, comparando suas classes.', 10, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (35, 9, 2, 'AE1', 'Resolver problemas que envolvam múltiplos e divisores de números naturais, em contextos reais.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (36, 9, 2, 'AE2', 'Comparar e ordenar números inteiros, utilizando, inclusive, a reta numérica como recurso.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (37, 9, 2, 'AE3', 'Resolver problemas que envolvam operações com números inteiros, por meio de estratégias diversas.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (38, 9, 2, 'AE4', 'Comparar e ordenar frações associadas às ideias de partes de inteiros, resultado da divisão, razão e operador, utilizando, inclusive, a reta numérica como apoio.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (39, 9, 2, 'AE5', 'Resolver problemas envolvendo as quatro operações fundamentais com frações, por meio de estratégias diversas de cálculo e representações visuais.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (40, 9, 2, 'AE6', 'Resolver problemas envolvendo as quatro operações fundamentais com números racionais nas formas fracionária e decimal, estabelecendo relações entre essas representações.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (41, 9, 2, 'AE7', 'Reconhecer e representar figuras geométricas planas no plano cartesiano, identificando suas características.', 7, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (42, 9, 2, 'AE8', 'Resolver problemas de cálculo de áreas de figuras planas, por meio da decomposição em quadrados, retângulos e triângulos, utilizando a equivalência entre áreas e estabelecendo expressões de cálculos.', 8, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (43, 9, 3, 'AE1', 'Resolver problemas que envolvam cálculos com números racionais, inclusive potências de expoentes inteiros, utilizando propriedades operatórias.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (44, 9, 3, 'AE2', 'Utilizar a relação entre potenciação e radiciação para representar raízes como potências de expoente fracionário e resolver problemas.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (45, 9, 3, 'AE3', 'Calcular o valor numérico de expressões algébricas, utilizando as propriedades das operações.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (46, 9, 3, 'AE4', 'Resolver problemas que possam ser representados por equações polinomiais do 1º grau, utilizando as propriedades da igualdade, e interpretá-los geometricamente.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (47, 9, 3, 'AE5', 'Resolver problemas com sistemas de equações do 1º grau com duas incógnitas, utilizando a representação gráfica no plano cartesiano.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (48, 9, 4, 'AE1', 'Resolver problemas envolvendo cálculos de potenciação e radiciação com números racionais, utilizando as propriedades operatórias.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (49, 9, 4, 'AE2', 'Reconhecer as condições necessárias e suficientes para que dois triângulos sejam semelhantes, utilizando-as para resolver problemas.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (50, 9, 4, 'AE3', 'Reconhecer relações métricas do triângulo retângulo, entre elas o teorema de Pitágoras, utilizando a semelhança de triângulos.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (51, 9, 4, 'AE4', 'Resolver problemas com a aplicação do teorema de Pitágoras.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (52, 9, 4, 'AE5', 'Reconhecer que existem segmentos de reta cujo comprimento não é expresso por número racional.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (53, 9, 4, 'AE6', 'Estimar a localização na reta numérica de números irracionais, reconhecendo que possuem representação decimal infinita e não periódica.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (54, 9, 4, 'AE7', 'Resolver problemas envolvendo os números reais, realizando operações e representando esses números na reta numérica.', 7, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (55, 9, 5, 'AE1', 'Utilizar operações com números reais, incluindo potenciação e radiciação, para resolver situações-problemas envolvendo grandezas, medidas e suas conversões.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (56, 9, 5, 'AE2', 'Resolver problemas geométricos que envolvem o Teorema de Pitágoras.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (57, 9, 5, 'AE3', 'Reconhecer as funções como relações de dependência unívoca entre duas variáveis, identificando as relações entre duas grandezas, em situações econômicas, sociais e das Ciências da Natureza.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (58, 9, 5, 'AE4', 'Resolver situações-problema que possam ser modeladas por funções polinomiais de 1º grau, resolvendo equações e usando representações algébricas e geométricas.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (59, 9, 6, 'AE1', 'Utilizar a notação científica para representar medidas e resolver problemas que empregam unidades de medida de diferentes grandezas.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (60, 9, 6, 'AE2', 'Modelar problemas que possam ser representados por equações polinomiais do 1º e 2º grau, em situações econômicas, sociais e das Ciências da Natureza.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (61, 9, 6, 'AE3', 'Resolver situações-problema que possam ser modeladas por funções exponenciais, resolvendo equações e utilizando das representações algébricas e geométricas.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (62, 9, 6, 'AE4', 'Resolver situações-problema que possam ser modeladas por funções logarítmicas, resolvendo equações e fazendo uso das representações algébricas e geométricas.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (63, 9, 7, 'AE1', 'Utilizar equações polinomiais de 1º e 2º grau para modelar situações-problema envolvendo grandezas e medidas.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (64, 9, 7, 'AE2', 'Resolver problemas do cotidiano que envolvem equações lineares simultâneas, utilizando técnicas algébricas e gráficas.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (65, 9, 7, 'AE3', 'Resolver problemas de contagem envolvendo agrupamentos ordenados ou não de elementos, recorrendo a estratégias diversas.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (66, 9, 7, 'AE4', 'Resolver problemas de probabilidade envolvendo eventos aleatórios não sucessivos, por meio da identificação do espaço amostral e da contagem de possibilidades.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (67, 9, 7, 'AE5', 'Resolver problemas de probabilidade em experimentos sucessivos, envolvendo eventos dependentes e independentes.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (68, 8, 1, 'AE1', 'Analisar as características de textos do campo jornalístico-midiático.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (69, 8, 1, 'AE2', 'Estabelecer relações entre gêneros jornalísticos, comparando suas características estruturais, linguísticas e temáticas.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (70, 8, 1, 'AE3', 'Analisar a função e o impacto do uso dos substantivos, verbos e adjetivos, identificando seus modificadores.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (71, 8, 1, 'AE4', 'Aplicar regras de ortografia e pontuação ao escrever textos, de acordo com as convenções da língua escrita.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (72, 8, 1, 'AE5', 'Utilizar diferentes estratégias de leitura em textos literários diversos, inferindo informações implícitas e analisando efeitos de sentido.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (73, 8, 1, 'AE6', 'Aplicar regras de concordância nominal e verbal em textos diversos, reconhecendo os efeitos de sentido gerados.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (74, 8, 1, 'AE7', 'Aplicar recursos lexicais (sinônimos, antônimos, homônimos, afixos, escolhas de vocabulário) e semânticos (relações de significado, efeitos de sentido, paráfrases, discurso direto/indireto), reconhecendo os sentidos produzidos nos textos.', 7, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (75, 8, 1, 'AE8', 'Analisar textos e espaços de reclamação e solicitação, reconhecendo suas características e funções sociais.', 8, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (76, 8, 1, 'AE9', 'Aplicar conhecimentos linguísticos e gramaticais na produção e análise de textos diversos.', 9, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (77, 8, 1, 'AE10', 'Analisar as características próprias de textos narrativos ficcionais, identificando efeitos de sentido gerados pela escolha de expressões diversas e recursos linguísticos e literários.', 10, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (78, 8, 1, 'AE11', 'Comparar informações sobre um mesmo fato divulgadas por diferentes veículos e mídias, analisando elementos que conferem credibilidade ao texto.', 11, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (79, 8, 1, 'AE12', 'Inferir os efeitos de sentido produzidos por palavras, imagens, pontuação e outros recursos em textos multimodais.', 12, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (80, 8, 1, 'AE13', 'Analisar textos normativos, jurídicos e reivindicatórios, reconhecendo suas marcas linguísticas e estruturais.', 13, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (81, 8, 2, 'AE1', 'Reconhecer diferentes propostas editoriais, analisando o tratamento dado ao fato noticiado.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (82, 8, 2, 'AE3', 'Identificar os efeitos de sentido causados por estratégias de modalização e argumentação em textos diversos.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (83, 8, 2, 'AE4', 'Comparar informações sobre um mesmo fato divulgadas por diferentes veículos e mídias, identificando elementos que contribuem para a credibilidade.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (84, 8, 2, 'AE5', 'Analisar as escolhas linguísticas que contribuem para a construção de sentidos em textos argumentativos.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (85, 8, 2, 'AE6', 'Analisar os elementos da narrativa em gêneros narrativos ficcionais diversos, reconhecendo suas características próprias.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (86, 8, 2, 'AE7', 'Interpretar efeitos de sentido produzidos pelo uso de recursos sonoros, semânticos e gráficos em poemas.', 7, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (87, 8, 2, 'AE9', 'Inferir a presença de valores sociais, culturais e humanos em diferentes visões de mundo em textos literários para reconhecer a riqueza cultural e linguística de diferentes nacionalidades.', 9, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (88, 8, 2, 'AE10', 'Identificar a função de gêneros de caráter avaliativo (prefácio, orelha, sinopse, resenha crítica e vlog), expressando opiniões e críticas pessoais com embasamento.', 10, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (89, 8, 3, 'AE1', 'Identificar os efeitos de sentido que fortalecem a persuasão nos textos publicitários.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (90, 8, 3, 'AE3', 'Analisar os efeitos de sentido gerados pelo uso de diferentes mecanismos de intertextualidade em textos variados.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (91, 8, 3, 'AE4', 'Analisar a presença de valores e de diferentes visões de mundo em textos literários de gêneros diversos.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (92, 8, 3, 'AE5', 'Analisar os efeitos de sentido produzidos por recursos linguísticos e gramaticais, paralinguísticos e cinésicos, como a gestualidade, em textos diversos.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (93, 8, 3, 'AE6', 'Analisar os efeitos de sentido produzidos pelos modificadores do verbo em textos diversos.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (94, 8, 3, 'AE7', 'Analisar as características próprias de gêneros textuais do campo jornalístico, identificando a posição assumida pelo autor e/ou veículo.', 7, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (95, 8, 3, 'AE8', 'Analisar a estrutura e os efeitos de sentido criados por recursos linguísticos em textos narrativos de diversos gêneros, como romances e contos.', 8, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (96, 8, 3, 'AE9', 'Analisar as características dos gêneros de divulgação científica, para identificar textos desse gênero.', 9, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (97, 8, 3, 'AE10', 'Reconhecer as formas de introduzir outras vozes em textos científicos.', 10, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (98, 8, 4, 'AE1', 'Participar de práticas compartilhadas de leitura e interpretação de obras literárias e manifestações artísticas, demonstrando preferências pessoais.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (99, 8, 4, 'AE2', 'Aplicar regras de escrita da norma-padrão em textos com estruturas sintáticas complexas.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (100, 8, 4, 'AE3', 'Analisar as características e os efeitos de sentido gerados pela linguagem e organização de textos literários narrativos.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (101, 8, 4, 'AE4', 'Analisar a estrutura, linguagem e temáticas próprias de gêneros jornalísticos, reconhecendo suas especificidades e função social.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (102, 8, 4, 'AE5', 'Analisar documentos legais e normativos, reconhecendo a importância deles para a garantia de direitos.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (103, 8, 4, 'AE6', 'Analisar textos de campanhas publicitárias, reconhecendo seu contexto de produção, circulação e recepção.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (104, 8, 4, 'AE7', 'Reconhecer as características dos gêneros de divulgação científica, envolvendo-se em produções estruturadas de textos desses gêneros.', 7, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (105, 8, 4, 'AE8', 'Avaliar argumentos em textos, posicionando-se frente à questão controversa de forma sustentada.', 8, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (106, 8, 4, 'AE9', 'Analisar diferentes práticas de interação digital para participar de forma ética e crítica em ambientes digitais.', 9, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (107, 8, 5, 'AE1', 'Identificar assimilações, rupturas e permanências na constituição da literatura brasileira, reconhecendo as peculiaridades estruturais e estilísticas de diferentes gêneros literários de cada período.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (108, 8, 5, 'AE2', 'Analisar elementos da sintaxe da língua portuguesa e as escolhas linguísticas de acordo com os diversos contextos comunicativos.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (109, 8, 5, 'AE3', 'Apreciar textos literários, observando efeitos de sentido gerados por escolhas linguísticas e figuras de linguagem.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (110, 8, 5, 'AE4', 'Identificar os efeitos de sentido decorrentes de escolhas linguísticas e da relação entre textos.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (111, 8, 5, 'AE5', 'Reconhecer a função social da literatura, por meio da leitura e escuta de textos, analisando textos literários de gêneros diversos e identificando gostos pessoais.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (112, 8, 5, 'AE6', 'Analisar os diferentes graus de parcialidade ou imparcialidade em textos noticiosos para conscientizar-se das escolhas do produtor e ter uma atitude crítica diante dos textos lidos.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (113, 8, 5, 'AE7', 'Analisar textos da esfera jornalístico-midiática, tendo em vista temas e acontecimentos de interesse local ou global, compartilhando percepções pessoais e críticas fundamentadas.', 7, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (114, 8, 5, 'AE8', 'Analisar textos publicitários e peças de campanhas publicitárias e políticas em contextos digitais ou impressos.', 8, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (115, 8, 5, 'AE9', 'Produzir textos reivindicatórios e argumentativos, como debates e manifestos, propondo soluções éticas e democráticas para problemas que envolvem a coletividade.', 9, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (116, 8, 5, 'AE10', 'Analisar obras significativas da literatura brasileira e de expressão portuguesa, indígena, africana e latino-americana, considerando suas características, contextos de produção e relações com o presente.', 10, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (117, 8, 6, 'AE1', 'Analisar as relações intertextuais e interdiscursivas entre obras de diferentes autores e gêneros literários, identificando os diálogos entre obras de um mesmo período e/ou de momentos históricos diversos.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (118, 8, 6, 'AE2', 'Analisar elementos da sintaxe da língua portuguesa, identificando escolhas linguísticas em textos diversos.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (119, 8, 6, 'AE3', 'Analisar obras significativas da literatura brasileira e de expressão portuguesa, indígena, africana e latino-americana, criticando os diferentes matizes culturais e visões de mundo que as tornam relevantes até os dias de hoje.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (120, 8, 6, 'AE4', 'Analisar textos do campo jornalístico-midiático para produzir textos autorais contextualizados.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (121, 8, 6, 'AE5', 'Analisar textos de divulgação científica de diferentes áreas do conhecimento, identificando suas características e criticando enfoques tendenciosos e superficiais.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (122, 8, 6, 'AE6', 'Produzir textos escritos e multissemióticos, considerando sua adequação às condições de produção e circulação.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (123, 8, 6, 'AE7', 'Produzir comentários apreciativos e críticos sobre obras artísticas diversas, garantindo crítica fundamentada por meio de gêneros multimodais.', 7, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (124, 8, 6, 'AE8', 'Analisar os efeitos de sentido decorrentes de escolhas linguísticas e da relação entre textos.', 8, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (125, 8, 6, 'AE9', 'Relacionar textos a seus contextos de produção, identificando suas condições de produção e função social.', 9, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (126, 8, 6, 'AE10', 'Analisar diferentes estratégias de persuasão e os efeitos de sentido construídos pelo uso de imagens, textos verbais e outros elementos usados para persuadir.', 10, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (127, 8, 6, 'AE11', 'Analisar as assimilações, rupturas e permanências na constituição da literatura brasileira, identificando as peculiaridades estruturais e estilísticas de diferentes gêneros literários de cada período.', 11, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (128, 8, 6, 'AE12', 'Utilizar variadas ferramentas de apoio a apresentações orais, considerando a clareza de conteúdo criado.', 12, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (129, 8, 7, 'AE1', 'Produzir textos escritos e/ou multimodais, considerando as etapas de produção necessárias para a escrita (planejamento, produção, revisão, edição e reescrita).', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (130, 8, 7, 'AE2', 'Avaliar obras da literatura brasileira, de expressão portuguesa, indígena, africana e latino-americana, considerando culturas e povos relacionados, reconhecendo sua importância para a construção de uma identidade nacional.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (131, 8, 7, 'AE3', 'Analisar as peculiaridades estruturais e estilísticas de diferentes gêneros literários, identificando o estilo, os temas e as influências dos movimentos literários aos quais pertencem.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (132, 8, 7, 'AE4', 'Avaliar os percursos argumentativos presentes em textos diversos, para posicionar-se de forma fundamentada e ética frente a questões de relevância social e cultural.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (133, 8, 7, 'AE5', 'Analisar textos de divulgação científica, avaliando suas fontes e reconhecendo enfoques de forma crítica e fundamentada para identificar e descartar fontes não confiáveis.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (134, 8, 7, 'AE6', 'Analisar textos jornalísticos, identificando elementos composicionais, linguagem e função do gênero, por meio do uso de ferramentas de curadoria.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (135, 8, 7, 'AE7', 'Analisar elementos da sintaxe da língua portuguesa, avaliando escolhas linguísticas de acordo com os diversos contextos comunicativos para produção de textos.', 7, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (136, 8, 7, 'AE8', 'Analisar diferentes obras e gêneros, identificando aspectos do contexto histórico, social e político, para reconhecer as relações de intertextualidade e de interdiscursividade existentes entre elas.', 8, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (137, 8, 7, 'AE9', 'Analisar textos e documentos legais e normativos, identificando motivações e finalidades das leis.', 9, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (138, 8, 7, 'AE10', 'Analisar o fenômeno da variação linguística, nos diferentes níveis e contextos, para fundamentar o respeito às variedades e combater preconceitos linguísticos.', 10, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (139, 4, 1, 'AE1', 'Praticar o handebol, utilizando habilidades técnico-táticas básicas e valorizando o trabalho coletivo e o protagonismo.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (140, 4, 1, 'AE2', 'Experimentar as provas do atletismo e do atletismo paralímpico, respeitando as diferenças individuais, valorizando a importância dessas práticas.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (141, 4, 1, 'AE3', 'Vivenciar danças urbanas para a criação e apresentação de coreografias, identificando elementos do hip-hop.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (142, 4, 1, 'AE4', 'Praticar exercícios da ginástica de condicionamento físico, identificando as capacidades físicas envolvidas.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (143, 4, 2, 'AE1', 'Praticar a capoeira, identificando suas características e elementos culturais, problematizando preconceitos e estereótipos.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (144, 4, 2, 'AE2', 'Vivenciar esportes de precisão, utilizando habilidades técnico- táticas básicas e adaptando regras, espaços e materiais para a prática.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (145, 4, 2, 'AE3', 'Experimentar o street dance, identificando seus quatro estilos principais e aplicando-os na criação e apresentação de coreografias.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (146, 4, 2, 'AE4', 'Experimentar exercícios físicos, identificando as capacidades físicas envolvidas, incentivando a prática regular.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (147, 4, 3, 'AE1', 'Praticar o voleibol e o vôlei sentado, usando habilidades técnico- táticas básicas e estratégias para solucionar desafios, discutindo estereótipos e preconceitos.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (148, 4, 3, 'AE2', 'Experimentar práticas de esportes de campo e taco, valorizando o trabalho coletivo e o protagonismo.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (149, 4, 3, 'AE3', 'Vivenciar as lutas do mundo, explorando técnicas e golpes de diferentes modalidades, respeitando os colegas.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (150, 4, 3, 'AE4', 'Experimentar o judô para cegos, analisando suas particularidades técnicas e táticas, discutindo estereótipos e preconceitos. Não há.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (151, 4, 4, 'AE1', 'Praticar o futsal e o futebol de cegos, aplicando habilidades técnico-táticas básicas e respeitando as diferenças individuais.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (152, 4, 4, 'AE2', 'Praticar o basquete e o basquete em cadeira de rodas, aplicando habilidades técnico-táticas básicas, respeitando as diferenças individuais.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (153, 4, 4, 'AE3', 'Experimentar lutas do mundo, conhecendo técnicas e golpes dessas modalidades, respeitando o oponente.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (154, 4, 4, 'AE4', 'Vivenciar o MMA, a esgrima e a esgrima em cadeira de rodas, explorando técnicas e golpes, adaptando os materiais para a prática.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (155, 4, 5, 'AE1', 'Vivenciar o futebol e suas variações, analisando os discursos midiáticos, valorizando a participação democrática, a equidade e o trabalho coletivo.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (156, 4, 5, 'AE2', 'Experimentar o goalball, analisando preconceitos e estereótipos, para refletir em relação à inclusão, cooperação, respeito e ética.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (157, 4, 5, 'AE3', 'Praticar o rugby e o futebol americano, compreendendo suas características e regras, analisando preconceitos presentes nas mídias.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (158, 4, 5, 'AE4', 'Experimentar as danças do Brasil e do mundo, apreciando suas manifestações culturais, para ampliação da sensibilidade, imaginação e criatividade.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (159, 4, 6, 'AE1', 'Praticar o tênis de mesa e o tênis de campo, identificando suas características, semelhanças e diferenças, para refletir sobre os estereótipos e as relações de poder presentes nessas práticas.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (160, 4, 6, 'AE2', 'Vivenciar as danças do mundo, valorizando suas diversidades, para reflexão sobre as diferentes manifestações culturais.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (161, 4, 7, 'AE1', 'Experimentar modalidades pouco praticadas no Brasil, explorando suas principais características, de modo a ampliar a cultura corporal de movimento.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (162, 4, 7, 'AE2', 'Praticar esportes de quadra de areia, adaptando regras, espaços e materiais, a fim de ampliar a cultura corporal de movimento.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (163, 7, 1, 'AE1', 'Descrever paisagens a partir de seus elementos constitutivos, comparando as modificações dos lugares de vivência em diferentes tempos.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (164, 7, 1, 'AE2', 'Relacionar os processos de urbanização, industrialização e desenvolvimento da agropecuária às transformações observadas nas paisagens, reconhecendo as diferentes formas de organização do espaço e as mudanças na interação entre sociedade e natureza.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (165, 7, 1, 'AE3', 'Examinar as representações cartográficas, reconhecendo a importância da Cartografia como forma de linguagem para a interpretação do espaço, diferenciando os elementos de mapas com diferentes representações e escalas.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (166, 7, 1, 'AE4', 'Classificar os principais tipos climáticos em diferentes lugares, com base em climogramas e mapas, explicando a diferença entre tempo e clima e a influência da circulação atmosférica.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (167, 7, 2, 'AE1', 'Comparar as regiões brasileiras em diferentes tempos, utilizando indicadores e representações (gráficos e mapas temáticos), relacionando desigualdades socioeconômicas e processos migratórios.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (168, 7, 2, 'AE2', 'Analisar como os fluxos econômicos e populacionais contribuem para a formação do território brasileiro e para o surgimento de tensões e conflitos, especialmente em São Paulo, com base em mapas temáticos.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (169, 7, 2, 'AE3', 'Analisar a distribuição territorial da população brasileira, relacionando os indicadores demográficos e considerando as diversidades étnico-raciais e culturais.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (170, 7, 2, 'AE4', 'Analisar o papel das redes de transporte e comunicação, explicando a evolução histórica e tecnológica dos fluxos materiais e imateriais em diferentes escalas.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (171, 7, 2, 'AE5', 'Relacionar os processos de industrialização e inovação tecnológica às transformações socioeconômicas, políticas, culturais e ambientais no território brasileiro.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (172, 7, 3, 'AE1', 'Analisar a influência política, econômica, social e cultural da Nova Ordem Mundial estabelecida no pós-Segunda Guerra sobre os Estados Unidos, a América Latina, a África, com destaque para o Brasil.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (173, 7, 3, 'AE2', 'Analisar os conflitos e as tensões geopolíticas contemporâneas na América e na África, aplicando os conceitos de Estado, nação, território, governo e país.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (174, 7, 3, 'AE3', 'Analisar o papel dos organismos internacionais e regionais na mediação de conflitos em fronteiras latino-americanas, considerando as consequências políticas, econômicas e sociais para a população.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (175, 7, 3, 'AE4', 'Analisar padrões econômicos e geopolíticos mundiais, relacionando a produção e o intercâmbio dos Estados Unidos e dos BRICS com a atuação de organizações mundiais e blocos econômicos regionais.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (176, 7, 3, 'AE5', 'Interpretar os efeitos do capital dos Estados Unidos e da China na reorganização das atividades econômicas globais, com destaque para o Brasil.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (177, 7, 4, 'AE1', 'Analisar o exercício da hegemonia europeia em diferentes tempos e lugares, usando representações cartográficas e gráficas para evidenciar desigualdades sociopolíticas e geopolíticas.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (178, 7, 4, 'AE2', 'Analisar fatos e situações da integração mundial econômica, política e cultural, comparando características e fenômenos da globalização com os da mundialização.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (179, 7, 4, 'AE3', 'Comparar regiões da Europa, Ásia e Oceania, a partir de mapas com diferentes projeções, para analisar as desigualdades sociopolíticas e geopolíticas decorrentes da hegemonia europeia.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (180, 7, 4, 'AE4', 'Investigar a atuação das corporações internacionais e das organizações econômicas mundiais, discutindo suas influências socioeconômicas e culturais no cotidiano das populações em diferentes regiões do mundo.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (181, 7, 5, 'AE1', 'Analisar os impactos socioambientais das ações humanas coletivas e individuais, selecionando, incorporando e promovendo as que favoreçam a consciência e a ética socioambiental, consumo responsável e a mitigação das mudanças climáticas.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (182, 7, 5, 'AE2', 'Analisar as relações entre elementos naturais e ações humanas, reconhecendo os impactos e a importância da gestão sustentável da água, do relevo e dos biomas.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (183, 7, 5, 'AE3', 'Utilizar a linguagem cartográfica de forma crítica e reflexiva.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (184, 7, 5, 'AE4', 'Avaliar os efeitos da globalização, das transformações tecnológicas e dos blocos econômicos sobre o mundo do trabalho e as condições de vida das diferentes gerações.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (185, 7, 5, 'AE5', 'Avaliar os impactos socioeconômicos e socioambientais das cadeias produtivas ligadas à exploração de recursos naturais e à agropecuária.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (186, 7, 5, 'AE6', 'Comparar os impactos socioambientais de diferentes modelos socioeconômicos em escala global, analisando as iniciativas e políticas governamentais voltadas à promoção da sustentabilidade.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (187, 7, 6, 'AE1', 'Analisar como diferentes regiões se organizam, considerando aspectos culturais, econômicos, ambientais, políticos e sociais, com base em dados demográficos e econômicos.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (188, 7, 6, 'AE2', 'Analisar transformações econômicas, fluxos migratórios e processos de globalização, especialmente no Brasil, compreendendo suas causas, efeitos e implicações para a economia, a sociedade e as relações internacionais.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (189, 7, 6, 'AE3', 'Analisar indicadores socioeconômicos do Brasil, relacionando-os às leis trabalhistas e à atuação do país na economia mundial.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (190, 7, 6, 'AE4', 'Analisar os significados de Estado, nação, território, fronteiras e vazios (espacial, temporal e cultural), considerando a formação histórica, disputas territoriais e identidades culturais, incluindo o contexto brasileiro.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (191, 7, 6, 'AE5', 'Analisar os processos de urbanização no Brasil e no mundo, relacionando a formação de cidades, megacidades e territórios ao papel de diferentes agentes e aos impactos socioambientais e socioculturais envolvidos.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (192, 7, 6, 'AE6', 'Avaliar dados de desigualdade no campo e de modelos de produção, identificando políticas públicas e discutindo as características do agronegócio contemporâneo.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (193, 2, 5, 'AE1', 'Analisar as transformações e conservações de matéria e energia em sistemas biológicos, associando processos celulares e interações ecológicas à sustentabilidade ambiental.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (194, 2, 5, 'AE2', 'Explicar o aquecimento global, avaliando suas relações com as mudanças climáticas e os riscos ambientais provocados pelas ações humanas.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (195, 2, 5, 'AE3', 'Analisar os impactos socioambientais das fontes de energia renováveis e não renováveis a partir das matrizes mundial e brasileira.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (196, 2, 5, 'AE4', 'Reconhecer os impactos da poluição ambiental nos sistemas fisiológicos humanos, identificando ações e tecnologias voltadas à prevenção e promoção da saúde individual, coletiva e ambiental.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (197, 2, 6, 'AE1', 'Reconhecer os riscos e benefícios das radiações para a saúde humana.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (198, 2, 6, 'AE2', 'Relacionar a meiose à reprodução e a mitose ao crescimento, manutenção dos tecidos e origem de cânceres.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (199, 2, 6, 'AE3', 'Avaliar os efeitos de intervenções humanas nos ecossistemas, destacando seus impactos sobre a biodiversidade e propondo ações voltadas à sustentabilidade e prevenção de zoonoses.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (200, 2, 6, 'AE4', 'Avaliar os benefícios e riscos dos defensivos agrícolas, relacionando sua composição, toxicidade e exposição aos processos de bioacumulação e biomagnificação.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (201, 2, 6, 'AE5', 'Analisar a importância da diversidade genética, discutindo sua relação com organismos geneticamente modificados e transgênicos, considerando os princípios de biossegurança, bioética e biodiversidade.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (202, 3, 1, 'AE1', 'Descrever as esferas que compõem a Terra, reconhecendo o surgimento da litosfera e suas transformações ao longo do tempo.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (203, 3, 1, 'AE2', 'Explicar os efeitos dos movimentos do Sistema Terra-Sol-Lua na ocorrência de fenômenos naturais, considerando as relações entre rotação e translação da Terra e a interação entre Sol e Lua.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (204, 3, 1, 'AE3', 'Classificar os tipos de rochas, identificando seus processos de formação e transformação do solo, como a fossilização em rochas sedimentares.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (205, 3, 1, 'AE4', 'Analisar os processos de separação de misturas do cotidiano, classificando as substâncias, as misturas e as mudanças de estado físico da matéria.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (206, 3, 2, 'AE1', 'Investigar a teoria da deriva continental, relacionando a correspondência entre os formatos das costas brasileira e africana aos processos da tectônica de placas.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (207, 3, 2, 'AE2', 'Identificar a composição da atmosfera e os fatores naturais e humanos que a modificam, relacionando-os aos impactos ambientais e à saúde do sistema respiratório humano.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (208, 3, 2, 'AE3', 'Distinguir o uso e o funcionamento de máquinas simples, com base no conceito de força e exemplos do cotidiano.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (209, 3, 2, 'AE4', 'Aplicar os conceitos de calor, temperatura e sensação térmica na análise das formas de propagação do calor e do equilíbrio termodinâmico.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (210, 3, 2, 'AE5', 'Analisar os impactos econômicos, culturais e sociais das inovações tecnológicas na sociedade, destacando as máquinas elétricas e seu uso consciente.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (211, 3, 2, 'AE6', 'Analisar os impactos socioambientais do uso de combustíveis fósseis, das queimadas e do desmatamento, reconhecendo suas consequências para os ecossistemas.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (212, 3, 2, 'AE7', 'Identificar o efeito estufa como um fenômeno natural, reconhecendo os impactos das ações humanas que o intensificam.', 7, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (213, 3, 2, 'AE8', 'Explicar as características de vírus, bactérias e fungos, identificando as doenças que causam e as formas de preveni-las.', 8, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (214, 3, 2, 'AE9', 'Caracterizar os ecossistemas brasileiros, explicando como os fatores bióticos e abióticos se relacionam às características da fauna e da flora, considerando a biodiversidade como elemento central.', 9, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (215, 3, 3, 'AE1', 'Identificar as mudanças físicas e comportamentais que ocorrem na puberdade, relacionando-as às interações entre os sistemas nervoso e endócrino.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (216, 3, 3, 'AE2', 'Comparar processos reprodutivos assexuados e sexuados em vegetais e animais, com base em mecanismos evolutivos e adaptativos.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (217, 3, 3, 'AE3', 'Analisar formas de prevenção das infecções sexualmente transmissíveis e da gravidez precoce, reconhecendo práticas de saúde sexual e reprodutiva.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (218, 3, 3, 'AE4', 'Discutir os efeitos do uso de substâncias psicoativas para propor ações de prevenção voltadas à saúde individual e coletiva.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (219, 3, 3, 'AE5', 'Descrever as principais estruturas e funções do sistema digestório e dos nutrientes, relacionando-os à classificação dos alimentos em processados, ultraprocessados e in natura.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (220, 3, 3, 'AE6', 'Explicar o funcionamento do sistema respiratório e os fatores que comprometem sua atividade, incluindo a poluição atmosférica e as doenças.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (221, 3, 3, 'AE7', 'Explicar o funcionamento do sistema circulatório e sua relação com o sistema imune, reconhecendo ações que contribuem para a prevenção de doenças.', 7, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (222, 3, 4, 'AE1', 'Analisar a importância do acesso a informações científicas de qualidade, considerando os critérios de confiabilidade das fontes e avaliando os impactos da desinformação.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (223, 3, 4, 'AE2', 'Identificar os modelos que estruturam a matéria, reconhecendo a evolução histórica dos modelos atômicos e a classificação dos elementos químicos.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (224, 3, 4, 'AE3', 'Explicar as mudanças de estado físico, relacionando-as à estrutura molecular, aos estados de organização da matéria e às temperaturas de fusão e ebulição.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (225, 3, 4, 'AE4', 'Analisar as transformações químicas e as relações entre reagentes e produtos, aplicando as leis ponderais.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (226, 3, 4, 'AE5', 'Classificar as radiações eletromagnéticas de acordo com suas frequências e aplicações em diferentes tecnologias, reconhecendo suas implicações para a saúde e para o cotidiano.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (227, 3, 4, 'AE6', 'Investigar as características das ondas mecânicas e eletromagnéticas, reconhecendo como esses conhecimentos revolucionaram os sistemas de comunicação humana.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (228, 3, 4, 'AE7', 'Explicar os processos de hereditariedade e as aplicações da biotecnologia, articulando-os à genética clássica e à evolução biológica.', 7, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (229, 3, 4, 'AE8', 'Explicar a transmissão das características hereditárias com base nas ideias de Mendel sobre fatores hereditários, gametas, segregação e fecundação, utilizando heredogramas.', 8, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (230, 3, 4, 'AE9', 'Explicar as ideias evolucionistas de Lamarck e Darwin, destacando seus contextos históricos e sua relevância para a compreensão da biodiversidade.', 9, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (231, 5, 5, 'AE1', 'Analisar as origens da Filosofia, seus campos de investigação e as características da atitude filosófica, considerando a importância do diálogo e da argumentação fundamentada.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (232, 5, 5, 'AE2', 'Analisar a produção artística, compreendendo a formação do gosto e exercitando a atitude crítica diante de padrões estéticos, conhecimentos e valores historicamente construídos.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (233, 5, 5, 'AE3', 'Analisar as relações intergeracionais no Brasil e no mundo contemporâneo, problematizando estereótipos e a prática do etarismo, e reconhecendo a importância dos estatutos de proteção às diferentes fases da vida.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (234, 5, 5, 'AE4', 'Identificar formas de violência, suas causas e significados, avaliando mecanismos de enfrentamento com base em argumentos éticos.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (235, 5, 5, 'AE5', 'Analisar a formação do Estado e a legitimidade do poder político, aplicando o conceito de soberania a partir de pensadores do contratualismo, liberalismo e republicanismo clássicos.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (236, 6, 5, 'AE1', 'Resolver problemas envolvendo corpos em movimento com velocidade e/ou aceleração constantes, representando trajetória, posição, velocidade e aceleração por meio de funções, gráficos e tabelas.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (237, 6, 5, 'AE2', 'Analisar situações de equilíbrio e de movimento acelerado, aplicando grandezas escalares e vetoriais com operações algébricas e vetoriais, com base nas Leis de Newton.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (238, 6, 5, 'AE3', 'Aplicar os princípios de conservação da energia e da quantidade de movimento na análise de sistemas mecânicos que envolvem trabalho, potência, impulso e colisões.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (239, 6, 6, 'AE1', 'Interpretar sistemas térmicos, aplicando leis e modelos da Termodinâmica para descrever as transformações de energia associadas à transferência de calor e às variações de temperatura.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (240, 6, 6, 'AE2', 'Aplicar princípios da Termodinâmica na análise, avaliação e construção de sistemas térmicos, relacionando sua eficiência a contextos de uso sustentável da energia.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (241, 6, 7, 'AE1', 'Analisar interações eletrostáticas entre cargas e campos elétricos, calculando forças, potenciais e energia associada a situações práticas e simuladas.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (242, 6, 7, 'AE2', 'Analisar circuitos elétricos, calculando corrente, resistência, tensão, potência e consumo de energia.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (243, 10, 5, 'AE1', 'Analisar a evolução histórica e científica dos modelos atômicos, reconhecendo-os como uma construção humana e compreendendo como eles explicam fenômenos do cotidiano.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (244, 10, 5, 'AE2', 'Analisar a origem, a classificação e a organização dos elementos químicos na Tabela Periódica, reconhecendo as características dos radioisótopos e as leis das emissões radioativas.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (245, 10, 5, 'AE3', 'Analisar as diversas interações entre átomos, entre moléculas e entre átomos e moléculas, bem como seus efeitos nas propriedades dos materiais, distinguindo as ligações químicas e as interações intermoleculares das moléculas essenciais à vida.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (246, 10, 5, 'AE4', 'Analisar situações-problema em processos tecnológicos, produtivos, sustentáveis e ambientais, reconhecendo a quantidade de matéria e energia envolvidas nas transformações químicas.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (247, 10, 6, 'AE1', 'Analisar a composição, as propriedades e as aplicações dos metais pesados e dos plásticos para avaliar os impactos socioambientais e os riscos à saúde decorrentes de sua extração, produção e descarte inadequado.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (248, 10, 6, 'AE2', 'Analisar a eficiência e os impactos socioambientais dos combustíveis renováveis e não renováveis, calculando a entalpia das reações químicas e identificando a dependência mundial dos combustíveis não renováveis.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (249, 10, 6, 'AE3', 'Analisar os compostos orgânicos e as suas aplicações, nomeando, classificando e identificando as funções orgânicas, para elaborar ações de prevenção e de promoção da saúde e do bem-estar.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (250, 10, 6, 'AE4', 'Analisar caso de isomeria plana nos macro e micronutrientes, identificando as propriedades e as vantagens e desvantagens do uso dos compostos orgânicos na produção de alimentos.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (251, 10, 6, 'AE5', 'Analisar a estrutura, a síntese e as aplicações de polímeros naturais e sintéticos, identificando as principais reações de polimerização e casos de isomeria cis-trans.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (252, 11, 6, 'AE1', 'Analisar a especificidade do conhecimento sociológico como campo científico, reconhecendo seus conceitos fundamentais e teorias clássicas da relação entre indivíduo e sociedade, aplicando-os na análise de processos sociais.', 1, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (253, 11, 6, 'AE2', 'Analisar a relação entre o indivíduo e o contexto sociocultural em que vive, aplicando conceitos da antropologia e da sociologia, identificando os processos que tornam os humanos seres sociais e culturais.', 2, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (254, 11, 6, 'AE3', 'Elaborar hipóteses e argumentos a partir da análise de evidências de processos sociais, culturais e políticos, de informações confiáveis e da coleta e sistematização de dados.', 3, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (255, 11, 6, 'AE4', 'Analisar as relações entre sujeitos e grupos no mundo contemporâneo, aplicando os conceitos de diferenciação, produção social da diferença, estratificação e classe social, para explicar problemas de convivência, exclusão social, marginalização e desigualdades.', 4, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (256, 11, 6, 'AE5', 'Analisar as diferentes formas de violência presentes no cotidiano, compreendendo suas causas sociais, culturais e institucionais e discutindo seus impactos na convivência social.', 5, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (257, 11, 6, 'AE6', 'Analisar situações da vida cotidiana, estilos de vida, valores e condutas, aplicando conceitos sociológicos, para desnaturalizar formas de desigualdade, preconceito, intolerância, discriminação e violência presentes nas relações étnico-raciais, de gênero e em outros contextos sociais.', 6, NOW());
INSERT INTO curriculum_learning_objectives (id, discipline_id, grade_level_id, ae_codigo, descricao, sort_order, created_at) VALUES (258, 11, 6, 'AE7', 'Analisar os princípios dos Direitos Humanos, como a dignidade humana, a igualdade e a não violência, para identificar práticas cotidianas de violação e avaliar ações que promovem a defesa desses direitos.', 7, NOW());
